mapper.update:
update user
username = #{username}, name = #{name}, phone = #{phone}, email = #{email}, gender = #{gender}, status = #{status}, dept_id = #{deptId}, role_id = #{roleId}, image = #{image}, remark = #{remark}, update_time = #{updateTime}
where id = #{id}

mapper.select:
select u.id, u.username, u.name, u.phone, u.email, u.gender, u.status, u.dept_id, u.role_id, u.image, u.remark, d.name deptName,r.name roleName,u.create_time, u.update_time from user u left join dept d on u.dept_id = d.id left join role r on u.role_id = r.id
and u.name like concat('%',#{name},'%')
and phone = like concat('%',#{phone},'%')
and u.status = #{status}
and u.dept_id = #{deptId}
